--
-- Table structure for table `equipment`
--

DROP TABLE IF EXISTS `equipment`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `equipment` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `school_id` bigint unsigned NOT NULL,
  `property_no` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `old_property_no` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `serial_number` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `item_type` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `equipment_type` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `brand` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `model` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `specifications` text COLLATE utf8mb4_unicode_ci,
  `unit_of_measure` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'Unit',
  `category` enum('High-Value','Low-Value') COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'High-Value',
  `classification` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'Machinery and Equipment for ICT',
  `gl_sl_code` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `uacs_code` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `is_dcp` tinyint(1) NOT NULL DEFAULT '0',
  `dcp_package` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `dcp_year` year DEFAULT NULL,
  `is_non_dcp` tinyint(1) NOT NULL DEFAULT '0',
  `acquisition_cost` decimal(12,2) DEFAULT NULL,
  `acquisition_date` date DEFAULT NULL,
  `received_date` date DEFAULT NULL,
  `estimated_useful_life` smallint unsigned DEFAULT NULL,
  `mode_of_acquisition` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `source_of_acquisition` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `donor` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `source_of_funds` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `pmp_reference_no` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `supporting_doc_type_acquisition` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `supporting_doc_no_acquisition` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `supplier` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `under_warranty` tinyint(1) NOT NULL DEFAULT '0',
  `warranty_end_date` date DEFAULT NULL,
  `equipment_location` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `is_functional` tinyint(1) NOT NULL DEFAULT '1',
  `condition` enum('Good','Fair','Poor','Unserviceable') COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'Good',
  `accountability_status` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL DEFAULT 'unassigned',
  `disposition_status` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `remarks` text COLLATE utf8mb4_unicode_ci,
  `qr_code` text COLLATE utf8mb4_unicode_ci,
  `transaction_type` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `supporting_doc_type_issuance` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `supporting_doc_no_issuance` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  `deleted_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `equipment_property_no_unique` (`property_no`),
  KEY `equipment_school_id_accountability_status_index` (`school_id`,`accountability_status`),
  KEY `equipment_is_dcp_condition_index` (`is_dcp`,`condition`),
  KEY `equipment_equipment_type_index` (`equipment_type`),
  CONSTRAINT `equipment_school_id_foreign` FOREIGN KEY (`school_id`) REFERENCES `schools` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=622 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

